// rch/src/tui/keybindings.rs

pub struct KeyBindings {
    pub quit: Vec<KeyCode>,
    pub drain_worker: KeyCode,
    pub enable_worker: KeyCode,
    pub refresh: KeyCode,
    pub help: KeyCode,
    pub navigate_up: KeyCode,
